const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const itemPremium = (item: { type: string }): number => {
  const base = BASE_PREMIUM[item.type];
  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
};

export const runScenario = (input: any): { results: unknown[] } => {
  const items: { type: string }[] = input.steps[0].items;
  const premium =
    items.reduce((total, item) => total + itemPremium(item), 0) + PROCESSING_FEE;
  return { results: [{ premium }] };
};

