  // Policy-wide modifiers
  it.todo("long-standing customer (≥2 years) gets 20% loyalty discount on policy base");
  it.todo("customer with exactly 2 years gets loyalty discount");
  it.todo("first ever contract: 10% first-insurance surcharge applies");
  it.todo("follow-up contract (2nd quote): 15% discount applies");
  it.todo("each item is treated as a first insurance for the 10% surcharge");

  // Integration examples from spec
  it.todo("newcomer with cursed sword (steel, ench 3): premium 165 G");
  it.todo("long-standing customer's second contract cursed sword ench 7: premium 160 G");
  it.todo("cursed sword + plain amulet (newcomer): 210 G before fee and first-insurance");

  // Rounding
  it.todo("premium rounds up in MHPCO's favor (197.5 → 198)");

  // Claim: standard cases
  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full - 100 deductible)");
  it.todo("damage to a rune, 200 → payout 100 (full - 100 deductible)");

  // Claim: special clauses
  it.todo("damage to item with enchantment ≥ 8 is 50% of damage, then deductible");
  it.todo("dragon-material sword fully reimbursed, then deductible");
  it.todo("dragon-material sword ench 9: 50% rule wins (both apply), then deductible");
  it.todo("dragon-material sword ench 5, damage 800 → payout 700");
  it.todo("dragon-material sword ench 8 damage 1000 → payout 400 (50% applies first)");

  // Deductible per damage event
  it.todo("dragon attack damages sword 500 and amulet 300 → payout 600 (deductible per item)");

  // Cap
  it.todo("policy of sword + amulet: insurance sum 1600, cap 3200");
