  it.todo("dragon attack damages both swords (two entries) → each gets own deductible");

  // CLI / scenario
  it.todo("CLI: scenario with single quote step writes premium to results");
  it.todo("CLI: scenario with quote then claim writes both premium and payout/remainingCap");
  it.todo("CLI: schema example produces correct results");

  // Errors
