import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Empty / processing fee only
  it("empty item list → premium 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // Single main item base premiums
  it("single plain sword (no modifiers, newcomer first ever contract) → 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("single plain amulet → 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("single plain staff → 93 G (80 + 8 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 93 });
  });
  it("single plain potion → 49 G (40 + 4 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 49 });
  });

  // Components (runes/moonstones) and block discount
  it("2 runes (newcomer) → 60 G (2*25 base = 50 + 5 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("3 runes (block applies) → 71 G (60 base + 6 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("4 runes (no block) → 115 G (4*25=100 base + 10 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("2 runes + 1 moonstone (no block) → 87.5+5=... → rounded up: 88 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    // base 75 + 7.5 first ins = 82.5 + 5 fee = 87.5 -> rounded up = 88
    expect(result.results[0]).toEqual({ premium: 88 });
  });
  it("3 runes + 3 moonstones (two blocks) → 137 G (120 base + 12 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 137 });
  });

  // Item-specific modifiers
  it("cursed sword (newcomer) → 165 G (100 base + 50 curse + 10 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 165 });
  });
  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed + enchantment 5 sword applies both surcharges");

  // Policy-wide modifiers
  it.todo("long-standing customer (≥2 years) gets 20% loyalty discount on policy base");
  it.todo("customer with exactly 2 years gets loyalty discount");
  it.todo("first ever contract: 10% first-insurance surcharge applies");
  it.todo("follow-up contract (2nd quote): 15% discount applies");
  it.todo("each item is treated as a first insurance for the 10% surcharge");

  // Integration examples from spec
  it.todo("newcomer with cursed sword (steel, ench 3): premium 165 G");
  it.todo("long-standing customer's second contract cursed sword ench 7: premium 160 G");
  it.todo("cursed sword + plain amulet (newcomer): 210 G before fee and first-insurance");

  // Rounding
  it.todo("premium rounds up in MHPCO's favor (197.5 → 198)");

  // Claim: standard cases
  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full - 100 deductible)");
  it.todo("damage to a rune, 200 → payout 100 (full - 100 deductible)");

  // Claim: special clauses
  it.todo("damage to item with enchantment ≥ 8 is 50% of damage, then deductible");
  it.todo("dragon-material sword fully reimbursed, then deductible");
  it.todo("dragon-material sword ench 9: 50% rule wins (both apply), then deductible");
  it.todo("dragon-material sword ench 5, damage 800 → payout 700");
  it.todo("dragon-material sword ench 8 damage 1000 → payout 400 (50% applies first)");

  // Deductible per damage event
  it.todo("dragon attack damages sword 500 and amulet 300 → payout 600 (deductible per item)");

  // Cap
  it.todo("policy of sword + amulet: insurance sum 1600, cap 3200");
  it.todo("cursed sword cap is based on unmodified insurance value (cap 2000)");
  it.todo("policy of sword + 3 runes: insurance sum 1750 (block doesn't affect sum)");
  it.todo("two claims of 1500 against sword (cap 2000): first 1400 then 600, remainingCap 0");

  // Payout rounding
  it.todo("payout rounds down in MHPCO's favor (350.5 → 350)");

  // Multiple same type
  it.todo("policy with two swords: insurance sum 2000, cap 4000");
  it.todo("dragon attack damages both swords (two entries) → each gets own deductible");

  // CLI / scenario
  it.todo("CLI: scenario with single quote step writes premium to results");
  it.todo("CLI: scenario with quote then claim writes both premium and payout/remainingCap");
  it.todo("CLI: schema example produces correct results");

  // Errors
  it.todo("quote with unknown item type → exits non-zero, error to stderr");
  it.todo("claim referencing item not on policy → exits non-zero");
  it.todo("claim with negative damage amount → exits non-zero");
  it.todo("claim with more damages of a type than insured → exits non-zero");
});

